export interface GenerationState {
  isLoading: boolean;
  error: string | null;
  generatedImageUrl: string | null;
  step: 'idle' | 'analyzing_link' | 'analyzing_style' | 'generating_image';
}

export interface NewsInfo {
  topic: string;
