}

import { GoogleGenAI, Type } from "@google/genai";
import { NewsInfo, StyleAnalysis } from "../types";

const getAIClient = () => {
  return new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
};

export const analyzeNewsLink = async (url: string): Promise<NewsInfo> => {
  const ai = getAIClient();
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: `Analyze this news link: ${url}. Provide the main topic, 5 visual keywords that describe the subject, and a one-sentence summary.`,
    config: {
      tools: [{ googleSearch: {} }],
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          topic: { type: Type.STRING },
          visualKeywords: { 
            type: Type.ARRAY, 
            items: { type: Type.STRING } 
          },
          summary: { type: Type.STRING }
        },
        required: ["topic", "visualKeywords", "summary"]
      }
    }
  });

  return JSON.parse(response.text);
};

export const analyzeStyle = async (base64Image: string): Promise<StyleAnalysis> => {
  const ai = getAIClient();
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: {
      parts: [
        { inlineData: { data: base64Image, mimeType: 'image/png' } },
        { text: "Analyze the tone, manner, and aesthetic nuance of this image. Focus on mood, specific color palette, artistic technique (e.g., minimalist, 3D, photography, illustration), and lighting." }
      ]
    },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          mood: { type: Type.STRING },
          colors: { type: Type.ARRAY, items: { type: Type.STRING } },
          technique: { type: Type.STRING },
          lighting: { type: Type.STRING }
        },
        required: ["mood", "colors", "technique", "lighting"]
      }
    }
  });

  return JSON.parse(response.text);
};

export const generateCardBackground = async (news: NewsInfo, style: StyleAnalysis): Promise<string> => {
  const ai = getAIClient();

  const prompt = `Create a high-quality professional card news background image (640x640) about "${news.topic}". 
  Visual keywords: ${news.visualKeywords.join(', ')}.
  STRICT STYLE REQUIREMENTS:
  - Overall Mood: ${style.mood}
  - Color Palette: ${style.colors.join(', ')}
  - Artistic Technique: ${style.technique}
  - Lighting: ${style.lighting}

  The image must be clean, spacious enough to overlay text later (do NOT include any text in the image), and maintain the professional tone of a news card.`;

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: { parts: [{ text: prompt }] },
    config: {
      imageConfig: {
        aspectRatio: "1:1",
      }
    }
  });

  for (const part of response.candidates[0].content.parts) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }

  throw new Error("No image data found in response");
};

