import React, { useState, useRef, useEffect } from 'react';
import Header from './components/Header';
import { GenerationState, CardContent, NewsInfo } from './types';
import { analyzeNewsLink, analyzeStyle, generateCardBackground } from './services/geminiService';

const App: React.FC = () => {
  const [url, setUrl] = useState('');
  const [referenceImage, setReferenceImage] = useState<File | null>(null);
  const [previewUrl, setPreviewUrl] = useState<string | null>(null);
  const [state, setState] = useState<GenerationState>({
    isLoading: false,
    error: null,
    generatedImageUrl: null,
    step: 'idle'
  });

  const [cardContent, setCardContent] = useState<CardContent>({
    headline: '',
    summary: '',
    textColor: '#ffffff',
    textAlign: 'center'
  });

  const canvasRef = useRef<HTMLCanvasElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setReferenceImage(file);
      const reader = new FileReader();
      reader.onloadend = () => setPreviewUrl(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  const handleGenerate = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!url) return;

    setState({ ...state, isLoading: true, error: null, step: 'analyzing_link' });

    try {
      const newsInfo = await analyzeNewsLink(url);
      setCardContent(prev => ({
        ...prev,
        headline: newsInfo.suggestedHeadline,
        summary: newsInfo.suggestedSummary
      }));

      let styleInfo = {
        mood: "Professional and modern",
        colors: ["Blue", "White", "Gray"],
        technique: "Corporate photography style",
        lighting: "Bright and even"
      };

      if (referenceImage) {
        setState(prev => ({ ...prev, step: 'analyzing_style' }));
        const reader = new FileReader();
        const base64 = await new Promise<string>((resolve) => {
          reader.onload = () => resolve((reader.result as string).split(',')[1]);
          reader.readAsDataURL(referenceImage);
        });
        styleInfo = await analyzeStyle(base64);
      }

      setState(prev => ({ ...prev, step: 'generating_image' }));
      const imageUrl = await generateCardBackground(newsInfo, styleInfo);

      setState({
        isLoading: false,
        error: null,
        generatedImageUrl: imageUrl,
        step: 'idle'
      });
    } catch (err: any) {
      setState({
        isLoading: false,
        error: err.message || 'Something went wrong.',
        generatedImageUrl: null,
        step: 'idle'
      });
    }
  };

  useEffect(() => {
    if (state.generatedImageUrl && canvasRef.current) {
      const canvas = canvasRef.current;
      const ctx = canvas.getContext('2d');
      if (!ctx) return;

      const img = new Image();
      img.crossOrigin = "anonymous";
      img.src = state.generatedImageUrl;
      img.onload = () => {
        // Clear and Draw Background
        ctx.clearRect(0, 0, 640, 640);
        ctx.drawImage(img, 0, 0, 640, 640);

        // Add Dark Gradient Overlay for readability
        const gradient = ctx.createLinearGradient(0, 300, 0, 640);
        gradient.addColorStop(0, 'rgba(0,0,0,0)');
        gradient.addColorStop(1, 'rgba(0,0,0,0.7)');
        ctx.fillStyle = gradient;
        ctx.fillRect(0, 300, 640, 340);

        // Text Settings
        ctx.fillStyle = cardContent.textColor;
        ctx.textAlign = cardContent.textAlign;
        const xPos = cardContent.textAlign === 'center' ? 320 : cardContent.textAlign === 'left' ? 40 : 600;

        // Draw Headline
        ctx.font = 'bold 42px Inter, sans-serif';
        ctx.shadowColor = 'rgba(0,0,0,0.5)';
        ctx.shadowBlur = 10;
        ctx.fillText(cardContent.headline, xPos, 500);

        // Draw Summary
        ctx.font = '300 20px Inter, sans-serif';
